function chooseFirstFabric() {
  const fabricAttr = app.helpers.getAttribute('fabric');
  if (fabricAttr) {
    const { values } = fabricAttr;
    const firstSelectable = values.find(v => v.selectable && !v.selected);
    if (firstSelectable) {
      configure.run('selectValue', {
        ca: { id: fabricAttr.id },
        av: { id: firstSelectable.id }
      });
      app.mergedParams.noColorsAvailable = false;
      app.cart.updateAddToCart();
    }
